// Calculate signal_week (Monday of current week) and generate run metadata
function getMondayOfWeek(date) {
  const d = new Date(date);
  const day = d.getDay();
  const diff = d.getDate() - day + (day === 0 ? -6 : 1);
  d.setDate(diff);
  return d.toISOString().split('T')[0];
}

// Generate UUID v4
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const now = new Date();
const signalWeek = getMondayOfWeek(now);

return [{
  json: {
    signal_week: signalWeek,
    week_of: signalWeek,
    run_id: uuidv4(),
    started_at: now.toISOString()
  }
}];

// Normalize the Supabase response and check if we have signals
// n8n HTTP Request can return Supabase array responses in different formats:
// - As individual items (one per row) if array is non-empty
// - As a single item containing an empty array if no rows
// This code node normalizes both cases.

const allItems = $input.all();
const signals = [];

for (const item of allItems) {
  // If the item itself is a signal (has an id field), add it
  if (item.json && item.json.id) {
    signals.push(item.json);
  }
  // If the item is an array of signals (Supabase returned as array)
  else if (Array.isArray(item.json)) {
    for (const sig of item.json) {
      if (sig && sig.id) {
        signals.push(sig);
      }
    }
  }
}

if (signals.length === 0) {
  return [{ json: { _empty: true, signal_count: 0 } }];
}

// Return all signals as individual items, plus metadata on the first
return signals.map((sig, i) => ({
  json: {
    ...sig,
    _empty: false
  }
}));

// Prepare signals for Claude clustering
// 1. Capture all signal IDs for later marking as processed (race-safe)
// 2. Truncate body_text to 500 chars for clustering prompt (saves tokens)
// 3. Build JSON string of all signals for Claude

const allItems = $input.all();
const signalArray = allItems.map(item => item.json);

// Capture all signal IDs for race-safe processing later
const signalIdsToProcess = signalArray.map(s => s.id);

// Build truncated signals for Claude clustering prompt
const signalsForClaude = signalArray.map(s => ({
  id: s.id,
  source: s.source,
  title: s.title || '',
  body_text: (s.body_text || '').substring(0, 500),
  keywords: s.keywords || [],
  topic_category: s.topic_category || '',
  platform_engagement: s.platform_engagement || {}
}));

return [{
  json: {
    signal_ids_to_process: signalIdsToProcess,
    signals_for_claude: JSON.stringify(signalsForClaude),
    signal_count: signalArray.length,
    full_signals: signalArray,
    week_of: $('Calc Week & Start Run').first().json.week_of
  }
}];

