// Parse the Claude clustering response
// Extract topics array, attach full signal data for each topic

const claudeResponse = $input.first().json;
const prepData = $('Prepare Signals for Clustering').first().json;
const fullSignals = prepData.full_signals;
const signalIdsToProcess = prepData.signal_ids_to_process;
const weekOf = prepData.week_of;

// Parse Claude response text
let topics;
try {
  const responseText = claudeResponse.content?.[0]?.text || '{}';
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  topics = parsed.topics || [];
} catch (e) {
  // If parsing fails, create a single topic from all signals
  topics = [{
    topic_title: 'Weekly HR/AI Research Roundup',
    angle: 'Aggregate of this week\'s top signals',
    signal_ids: signalIdsToProcess,
    key_data_points: ['Multiple signals aggregated due to clustering parse error']
  }];
}

// Build lookup map for full signal data
const signalMap = {};
for (const sig of fullSignals) {
  signalMap[sig.id] = sig;
}

// Output one item per topic with full signal data attached
const output = topics.map(topic => {
  // Look up full signals for this topic
  const topicSignals = (topic.signal_ids || []).map(id => signalMap[id]).filter(Boolean);

  return {
    json: {
      topic_title: topic.topic_title,
      angle: topic.angle,
      signal_ids: topic.signal_ids || [],
      key_data_points: topic.key_data_points || [],
      signals: topicSignals,
      week_of: weekOf,
      signal_ids_to_process: signalIdsToProcess,
      signal_count: signalIdsToProcess.length,
      topic_count: topics.length
    }
  };
});

return output;

// Parse Claude scoring response, validate ranges, calculate total score
// Build insert payload for topic_recommendations table

const claudeResponse = $input.first().json;
const topicData = $('Score Topics (Batch)').first().json;

// Parse Claude response
let scores;
try {
  const responseText = claudeResponse.content?.[0]?.text || '{}';
  const cleaned = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scores = JSON.parse(cleaned);
} catch (e) {
  // Default scores if parsing fails
  scores = {
    engagement_score: 5,
    freshness_score: 5,
    gap_score: 5,
    positioning_score: 5,
    format_score: 5,
    recommended_format: 'text',
    recommended_series: 'flex',
    hook_suggestion: topicData.topic_title,
    scoring_rationale: 'Default scores applied due to parse error'
  };
}

// Validate and clamp score ranges
function clamp(val, min, max) {
  const num = parseInt(val) || 0;
  return Math.max(min, Math.min(max, num));
}

const engagementScore = clamp(scores.engagement_score, 0, 25);
const freshnessScore = clamp(scores.freshness_score, 0, 25);
const gapScore = clamp(scores.gap_score, 0, 20);
// Positioning can be 0-18 (15 base + 3 AEO bonus)
const positioningScore = clamp(scores.positioning_score, 0, 18);
const formatScore = clamp(scores.format_score, 0, 15);

// Total score: sum of all dimensions (can exceed 100 due to AEO bonus -- by design)
const totalScore = engagementScore + freshnessScore + gapScore + positioningScore + formatScore;

// Validate recommended_format
const validFormats = ['text', 'carousel', 'data_graphic'];
const recommendedFormat = validFormats.includes(scores.recommended_format)
  ? scores.recommended_format
  : 'text';

// Validate recommended_series
const validSeries = ['not_being_told', 'compliance_radar', 'ask_ai_guy', 'flex'];
const recommendedSeries = validSeries.includes(scores.recommended_series)
  ? scores.recommended_series
  : 'flex';

// Build insert payload for topic_recommendations
return [{
  json: {
    week_of: topicData.week_of,
    topic_title: topicData.topic_title,
    angle: topicData.angle,
    total_score: totalScore,
    engagement_score: engagementScore,
    freshness_score: freshnessScore,
    gap_score: gapScore,
    positioning_score: positioningScore,
    format_score: formatScore,
    recommended_format: recommendedFormat,
    recommended_series: recommendedSeries,
    hook_suggestion: scores.hook_suggestion || '',
    key_data_points: topicData.key_data_points || [],
    source_signal_ids: topicData.signal_ids || [],
    status: 'pending',
    // Carry forward for later nodes
    signal_ids_to_process: topicData.signal_ids_to_process,
    signal_count: topicData.signal_count,
    topic_count: topicData.topic_count
  }
}];

// After all topics scored and inserted, prepare for marking signals processed
// Retrieve the signal_ids_to_process from the first topic item
const firstTopic = $('Parse Clustering Response').first().json;

return [{
  json: {
    signal_ids_to_process: firstTopic.signal_ids_to_process,
    signal_count: firstTopic.signal_count,
    topic_count: firstTopic.topic_count,
    week_of: firstTopic.week_of
  }
}];
